#include <stdio.h>
#include <ctype.h>
#include <limits.h>

int myAtoi(const char *s) {
    long long num = 0;
    int sign = 1;
    // skip leading spaces
    while (*s && isspace((unsigned char)*s)) s++;
    // sign
    if (*s == '-') { sign = -1; s++; }
    else if (*s == '+') { s++; }
    // digits
    while (*s && isdigit((unsigned char)*s)) {
        num = num * 10 + (*s - '0');
        if (sign == 1 && num > INT_MAX) return INT_MAX;
        if (sign == -1 && num > (long long)INT_MAX + 1) return INT_MIN;
        s++;
    }
    return (int)(sign * num);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char buf[256];
    for (int i = 0; i < T; ++i) {
        if (!fgets(buf, sizeof(buf), stdin)) buf[0] = '\0';
        // remove trailing newline
        buf[strcspn(buf, "\n")] = '\0';
        printf("%d\n", myAtoi(buf));
    }
    return 0;
}

