        num = num * 10 + (s[i] - '0');
        if (sign == 1 && num > INT_MAX) return INT_MAX;
        if (sign == -1 && num > (long long)INT_MAX + 1) return INT_MIN;
        ++i;
    }
    return (int)(sign * num);
}

