import sys

def myAtoi(s: str) -> int:
    i = 0
    n = len(s)
    # skip leading spaces
    while i < n and s[i].isspace():
        i += 1
    sign = 1
    if i < n and s[i] == '-':
        sign = -1
        i += 1
    elif i < n and s[i] == '+':
        i += 1
    num = 0
    while i < n and s[i].isdigit():
        num = num * 10 + int(s[i])
        if sign == 1 and num > 2**31 - 1:
            return 2**31 - 1
        if sign == -1 and num > 2**31:
            return -2**31
        i += 1
    return sign * num

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T + 1):
        line = data[i] if i < len(data) else ''
        out.append(str(myAtoi(line)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

